1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	const itemPremium = (item: { type: string }): number => {
13	  const base = BASE_PREMIUM[item.type];
14	  return base + base * FIRST_INSURANCE_SURCHARGE_RATE;
15	};
16	
17	export const runScenario = (input: any): { results: unknown[] } => {
18	  const items: { type: string }[] = input.steps[0].items;
19	  const runeCount = items.filter((item) => item.type === "rune").length;
20	  let premium: number;
21	  if (runeCount === 3) {
22	    premium = 60 + 60 * FIRST_INSURANCE_SURCHARGE_RATE + PROCESSING_FEE;
23	  } else {
24	    premium =
25	      items.reduce((total, item) => total + itemPremium(item), 0) + PROCESSING_FEE;
26	  }
27	  return { results: [{ premium }] };
28	};
